Here's how to test `DataFetcher` with proper timeout/cancellation handling in MSTest 3.x+:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, FakeHandler handler) CreateFetcher(
        HttpStatusCode status = HttpStatusCode.OK,
        string content = "")
    {
        var handler = new FakeHandler(status, content);
        var client = new HttpClient(handler);
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var (fetcher, _) = CreateFetcher(HttpStatusCode.OK, "hello");

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.NotFound);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)] // cooperative timeout — fires CancellationToken
    public async Task FetchAsync_WithTimeout_CompletesWithinLimit()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.OK, "fast");

        // Pass TestContext.CancellationToken so the test aborts cleanly on timeout
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_WhenCancelled_ThrowsOperationCanceled()
    {
        // Arrange — handler that delays, giving us time to cancel
        using var cts = new CancellationTokenSource();
        var handler = new DelayHandler(TimeSpan.FromSeconds(10));
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Cancel immediately
        cts.Cancel();

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Test doubles ---

    private sealed class FakeHandler(HttpStatusCode status, string content)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            var response = new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            };
            return Task.FromResult(response);
        }
    }

    private sealed class DelayHandler(TimeSpan delay) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(delay, cancellationToken); // throws on cancel
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext.CancellationToken` | Cooperates with `[Timeout]` — test aborts cleanly instead of hanging |
| `Assert.ThrowsExactlyAsync<T>` | Verifies the exact exception type (not `[ExpectedException]`) |
| Custom `HttpMessageHandler` | The correct seam for testing `HttpClient` — no mocking library needed |
| `sealed` test class + constructor injection | Modern MSTest best practice for perf and nullability |
| Pre-cancelled `CancellationTokenSource` | Deterministic cancellation test — no race conditions |

The critical detail: **always flow `TestContext.CancellationToken`** into async calls in any test with `[Timeout]`. Without it, the timeout attribute has no way to stop the work cooperatively, and the test can hang.
